      {
       "num": 40,
       "type": "FILL",
       "text": "- The _________ in offices is often too low for women.",
       "answer": "temperature",
       "explanation": "Standard office temperature settings are often too cold for female comfort.",
       "instruction": "Questions 31-40<br/>Complete the notes below."
      }
